documents.t:
Target Entity: phonecall { "subject": "{{ 'Booking Confirmation: ' | append source.name }}", "description": "Confirm booking details with customer.

Booking Details:
- Start: {{ source.starttime | date.format 'yyyy-MM-dd HH:mm' }}
- End: {{ source.endtime | date.format 'yyyy-MM-dd HH:mm' }}
- Resource: {{ source.resource.name }}
- Duration: {{ source.duration }} minutes", "scheduledend": "{{ date.now | date.add_hours 2 }}", "directioncode": true, "regardingobjectid_bookableresourcebooking@odata.bind": "/bookableresourcebookings({{ source.bookableresourcebookingid }})"} Explanation: Creates an outgoing phone call (directioncode: true) Includes all booking details in description Schedules call within 2 hours

Target Entity: task { "subject": "{{ 'Reminder: Upcoming booking - ' | append source.name }}", "description": "Reminder to prepare for upcoming booking.

Customer: {{ source.new_customerid.name }}
Location: {{ source.new_location }}
Notes: {{ source.new_specialinstructions }}", "scheduledend": "{{ source.starttime | date.add_days -1 }}", "prioritycode": 2, "regardingobjectid_bookableresourcebooking@odata.bind": "/bookableresourcebookings({{ source.bookableresourcebookingid }})", "template:condition": "{{ (source.starttime | date.diff date.now 'days') > 1 }}"} Only creates reminder if booking is more than 1 day away

Target Entity: phonecall { "subject": "{{ 'Post-Service Follow-up: ' | append source.name }}", "description": "Follow up with customer after service completion.

Service Date: {{ source.starttime | date.format 'yyyy-MM-dd' }}
Resource: {{ source.resource.name }}", "scheduledend": "{{ source.endtime | date.add_days 1 }}", "directioncode": true, "regardingobjectid_bookableresourcebooking@odata.bind": "/bookableresourcebookings({{ source.bookableresourcebookingid }})"}

Target Entity: task { "subject": "{{ 'Onboarding: ' | append source.name }}", "description": "Complete onboarding process for new account.

Account Details:
- Name: {{ source.name }}
- Industry: {{ source.industrycode }}
- Revenue: {{ source.revenue }}", "scheduledend": "{{ date.now | date.add_days 7 }}", "prioritycode": "{{ source.revenue > 1000000 ? 1 : 2 }}", "regardingobjectid_account@odata.bind": "/accounts({{ source.accountid }})", "ownerid@odata.bind": "/systemusers({{ source.ownerid }})"} Explanation: Creates a task due in 7 days Sets high priority for accounts with revenue > 1,000,000 Assigns to the account owner Links task to the account

Target Entity: annotation { "subject": "Welcome to {{ source.name }}", "notetext": "New account created on {{ date.now | date.format 'yyyy-MM-dd' }}.

Account Summary:
- Industry: {{ source.industrycode }}
- Employees: {{ source.numberofemployees }}
- Website: {{ source.websiteurl }}

Owned by: {{ source.owningbusinessunit.name }}", "objectid_account@odata.bind": "/accounts({{ source.accountid }})"}

Target Entity: phonecall { "subject": "{{ 'Qualification Call: ' | append source.name }}", "description": "Initial qualification call for opportunity {{ source.name }}.

Estimated Value: {{ source.estimatedvalue }}
Close Probability: {{ source.closeprobability }}%", "scheduledend": "{{ date.now | date.add_days 2 }}", "regardingobjectid_opportunity@odata.bind": "/opportunities({{ source.opportunityid }})", "template:condition": "{{ source.salesstage == 100000000 }}"} Only creates when opportunity is at Qualify stage (100000000)

Target Entity: appointment { "subject": "{{ 'Product Demo: ' | append source.name }}", "description": "Scheduled product demonstration.

Customer: {{ source.parentaccountid.name }}
Budget: {{ source.budgetamount }}", "scheduledstart": "{{ date.now | date.add_days 5 }}", "scheduledend": "{{ date.now | date.add_days 5 | date.add_hours 1 }}", "regardingobjectid_opportunity@odata.bind": "/opportunities({{ source.opportunityid }})", "template:condition": "{{ source.salesstage == 100000001 }}"} Only creates when opportunity is at Develop stage (100000001)

Target Entity: task { "subject": "{{ 'Prepare Proposal: ' | append source.name }}", "description": "Prepare and send proposal.

Details:
- Estimated Value: {{ source.estimatedvalue }}
- Decision Maker: {{ source.decisionmaker }}
- Competitors: {{ source.currentcompetitors }}", "scheduledend": "{{ date.now | date.add_days 3 }}", "prioritycode": 1, "regardingobjectid_opportunity@odata.bind": "/opportunities({{ source.opportunityid }})", "template:condition": "{{ source.salesstage == 100000002 }}"} Only creates when opportunity is at Propose stage (100000002)

Target Entity: task { "subject": "{{ '[URGENT] Escalation: ' | append source.title }}", "description": "High priority case requires immediate attention.

Case: {{ source.ticketnumber }}
Customer: {{ source.customerid.name }}
Description: {{ source.description | string.truncate 500 }}

SLA Deadline: {{ source.new_sladeadline }}", "scheduledend": "{{ date.now | date.add_hours 2 }}", "prioritycode": 1, "regardingobjectid_incident@odata.bind": "/incidents({{ source.incidentid }})", "template:condition": "{{ source.prioritycode == 1 }}"} Only creates for high-priority cases (prioritycode == 1)

Target Entity: phonecall { "subject": "{{ 'Follow-up: ' | append source.ticketnumber }}", "description": "Case has been open for extended period.

Status: {{ source.statuscode }}
Created: {{ source.createdon }}", "scheduledend": "{{ date.now | date.add_days 1 }}", "regardingobjectid_incident@odata.bind": "/incidents({{ source.incidentid }})", "template:condition": "{{ source.prioritycode <= 2 && !source.resolveby }}"}
